on conflict (id) do update
set
  name = excluded.name,
  rarity = excluded.rarity,
  points = excluded.points,
  description = excluded.description,
  origin = excluded.origin,
  temperament = excluded.temperament,
  size = excluded.size,
  lifespan = excluded.lifespan,
  reference_photo_url = excluded.reference_photo_url;

with dates as (
  select
    generate_series(
      timezone('Australia/Sydney', now())::date,
      timezone('Australia/Sydney', now())::date + 89,
      interval '1 day'
    )::date as feature_date,
    row_number() over () as rn
),
ordered_breeds as (
  select
    id,
    row_number() over (order by points desc, name asc) as rn,
    count(*) over () as total_count
  from public.breeds
)
insert into public.featured_breeds (breed_id, feature_date, is_active)
select
  ordered_breeds.id,
  dates.feature_date,
  dates.feature_date = timezone('Australia/Sydney', now())::date
from dates
join ordered_breeds
  on ordered_breeds.rn = ((dates.rn - 1) % ordered_breeds.total_count) + 1
on conflict (feature_date) do update
set
  breed_id = excluded.breed_id,
  is_active = excluded.is_active;

update public.featured_breeds
set is_active = feature_date = timezone('Australia/Sydney', now())::date
where feature_date between timezone('Australia/Sydney', now())::date
  and timezone('Australia/Sydney', now())::date + 89;
